.darma-loader-darma-custom-734 {
  color: var(--loader-color, #22c55e);
width: 15px;
aspect-ratio: 1;
position: relative;
animation: darma-loader-darma-custom-734-l9-0 1.5s infinite steps(2);
}
.darma-loader-darma-custom-734::before,
.darma-loader-darma-custom-734::after {
content: "";
position: absolute;
inset: 0;
border-radius: 50%;
background: currentColor;
}
.darma-loader-darma-custom-734::before {
box-shadow: 26px 0;
transform: translateX(-26px);
animation: darma-loader-darma-custom-734-l9-1 .75s infinite linear alternate;
}
.darma-loader-darma-custom-734::after {
transform: translateX(13px) rotate(0deg) translateX(13px);
animation: darma-loader-darma-custom-734-l9-2 .75s infinite linear alternate;
}
@keyframes darma-loader-darma-custom-734-l9-0 {
0% ,49.9% {transform: scale(1)}
50%,100% {transform: scale(-1)}
}
@keyframes darma-loader-darma-custom-734-l9-1 {
100%{box-shadow: 52px 0}
}
@keyframes darma-loader-darma-custom-734-l9-2 {
100%{transform: translateX(13px) rotate(-180deg) translateX(13px)}
}

